import itertools, math, collections, statistics, re, unicodedata, json, os, difflib

def tokens(s):
    return normalize(s).split()

def token_f1(a,b):
    ta=tokens(a); tb=tokens(b)
    ca=collections.Counter(ta); cb=collections.Counter(tb)
    inter = sum((ca & cb).values())
    if not ta or not tb:
        return 0.0
    p = inter/len(tb)
    r = inter/len(ta)
    if p+r==0:
        return 0.0
    return 2*p*r/(p+r), p, r, inter, len(tb), len(ta)

